import{_ as t,o as e,c as r,ai as d}from"./chunks/framework.SowO7O0D.js";const p=JSON.parse('{"title":"第七课：读懂财报三张表","description":"","frontmatter":{},"headers":[],"relativePath":"guide/07-financial-statements.md","filePath":"guide/07-financial-statements.md","lastUpdated":0}'),n={name:"guide/07-financial-statements.md"};function l(i,a,s,h,o,b){return e(),r("div",null,[...a[0]||(a[0]=[d(`<h1 id="第七课-读懂财报三张表" tabindex="-1">第七课：读懂财报三张表 <a class="header-anchor" href="#第七课-读懂财报三张表" aria-label="Permalink to “第七课：读懂财报三张表”">​</a></h1><p>买股票就是买公司。判断一家公司好不好，最权威的资料就是<strong>财报</strong>。</p><h2 id="一、财报从哪看" tabindex="-1">一、财报从哪看？ <a class="header-anchor" href="#一、财报从哪看" aria-label="Permalink to “一、财报从哪看？”">​</a></h2><table tabindex="0"><thead><tr><th>渠道</th><th>地址</th></tr></thead><tbody><tr><td>巨潮资讯网</td><td>cninfo.com.cn（官方最全）</td></tr><tr><td>东方财富</td><td>eastmoney.com</td></tr><tr><td>同花顺</td><td>10jqka.com.cn</td></tr><tr><td>雪球</td><td>xueqiu.com</td></tr></tbody></table><p>每个上市公司每年发布<strong>4次财报</strong>：</p><ul><li>一季报（4月）</li><li>半年报（8月）</li><li>三季报（10月）</li><li>年报（次年4月前）</li></ul><h2 id="二、资产负债表" tabindex="-1">二、资产负债表 <a class="header-anchor" href="#二、资产负债表" aria-label="Permalink to “二、资产负债表”">​</a></h2><h3 id="一句话理解" tabindex="-1">一句话理解 <a class="header-anchor" href="#一句话理解" aria-label="Permalink to “一句话理解”">​</a></h3><p><strong>公司有多少家当，欠了多少债。</strong></p><h3 id="生活比喻" tabindex="-1">生活比喻 <a class="header-anchor" href="#生活比喻" aria-label="Permalink to “生活比喻”">​</a></h3><p>就像你的个人资产清单：</p><ul><li>你有100万存款（资产）</li><li>欠银行80万房贷（负债）</li><li>净资产20万</li></ul><h3 id="关键科目" tabindex="-1">关键科目 <a class="header-anchor" href="#关键科目" aria-label="Permalink to “关键科目”">​</a></h3><table tabindex="0"><thead><tr><th>科目</th><th>含义</th></tr></thead><tbody><tr><td>总资产</td><td>公司所有家当加起来</td></tr><tr><td>总负债</td><td>公司欠的所有债</td></tr><tr><td>净资产（所有者权益）</td><td>总资产 - 总负债</td></tr></tbody></table><h3 id="判断要点" tabindex="-1">判断要点 <a class="header-anchor" href="#判断要点" aria-label="Permalink to “判断要点”">​</a></h3><blockquote><p>净资产 &gt; 总负债的50%，说明公司比较稳健。</p></blockquote><h2 id="三、利润表" tabindex="-1">三、利润表 <a class="header-anchor" href="#三、利润表" aria-label="Permalink to “三、利润表”">​</a></h2><h3 id="一句话理解-1" tabindex="-1">一句话理解 <a class="header-anchor" href="#一句话理解-1" aria-label="Permalink to “一句话理解”">​</a></h3><p><strong>公司赚钱了吗？赚了多少？</strong></p><h3 id="生活比喻-1" tabindex="-1">生活比喻 <a class="header-anchor" href="#生活比喻-1" aria-label="Permalink to “生活比喻”">​</a></h3><p>就像月收入账单：</p><ul><li>工资收入2万（营业收入）</li><li>扣除生活开销1.5万（营业成本）</li><li>净赚5000（净利润）</li></ul><h3 id="关键科目-1" tabindex="-1">关键科目 <a class="header-anchor" href="#关键科目-1" aria-label="Permalink to “关键科目”">​</a></h3><table tabindex="0"><thead><tr><th>科目</th><th>含义</th></tr></thead><tbody><tr><td>营业收入</td><td>卖产品/服务收到的钱</td></tr><tr><td>营业成本</td><td>生产和销售过程的花费</td></tr><tr><td>净利润</td><td>扣除所有费用后真正赚到的</td></tr></tbody></table><h3 id="判断要点-1" tabindex="-1">判断要点 <a class="header-anchor" href="#判断要点-1" aria-label="Permalink to “判断要点”">​</a></h3><blockquote><p>净利润连续3年增长的公司，说明基本面不错。</p></blockquote><h2 id="四、现金流量表" tabindex="-1">四、现金流量表 <a class="header-anchor" href="#四、现金流量表" aria-label="Permalink to “四、现金流量表”">​</a></h2><h3 id="一句话理解-2" tabindex="-1">一句话理解 <a class="header-anchor" href="#一句话理解-2" aria-label="Permalink to “一句话理解”">​</a></h3><p><strong>公司实际收到了多少现金？</strong></p><h3 id="生活比喻-2" tabindex="-1">生活比喻 <a class="header-anchor" href="#生活比喻-2" aria-label="Permalink to “生活比喻”">​</a></h3><p>你月入2万，但其中1万是年底奖金（还没到账），实际本月到手只有1万。现金流量表看的是&quot;真金白银&quot;。</p><h3 id="关键科目-2" tabindex="-1">关键科目 <a class="header-anchor" href="#关键科目-2" aria-label="Permalink to “关键科目”">​</a></h3><table tabindex="0"><thead><tr><th>活动</th><th>说明</th></tr></thead><tbody><tr><td>经营活动现金流</td><td>主营业务真实收到的钱</td></tr><tr><td>投资活动现金流</td><td>买设备、并购等投资花的钱</td></tr><tr><td>筹资活动现金流</td><td>借钱、发行股票等融资行为</td></tr></tbody></table><h3 id="判断要点-2" tabindex="-1">判断要点 <a class="header-anchor" href="#判断要点-2" aria-label="Permalink to “判断要点”">​</a></h3><blockquote><p><strong>经营现金流为负</strong>的公司要小心，说明主业不赚钱，靠融资活着。</p></blockquote><h2 id="五、财务最重要的原则" tabindex="-1">五、财务最重要的原则 <a class="header-anchor" href="#五、财务最重要的原则" aria-label="Permalink to “五、财务最重要的原则”">​</a></h2><blockquote><p>💡 <strong>利润可以&quot;做账&quot;，但现金流量表很难造假。</strong></p></blockquote><p>所以专业投资者最关注的指标：<strong>经营现金流 &gt; 净利润</strong></p><p>如果一家公司净利润很高，但经营现金流长期为负，就要怀疑利润的真实性。</p><h2 id="六、简化版财务筛选" tabindex="-1">六、简化版财务筛选 <a class="header-anchor" href="#六、简化版财务筛选" aria-label="Permalink to “六、简化版财务筛选”">​</a></h2><p>用东方财富的选股器，可以快速筛选：</p><table tabindex="0"><thead><tr><th>条件</th><th>建议值</th></tr></thead><tbody><tr><td>净利润增速</td><td>&gt;10%</td></tr><tr><td>净资产收益率(ROE)</td><td>&gt;15%</td></tr><tr><td>资产负债率</td><td>&lt;60%</td></tr><tr><td>市盈率(PE)</td><td>&lt;30（成长股可接受更高）</td></tr></tbody></table><h2 id="七、三张表的关系" tabindex="-1">七、三张表的关系 <a class="header-anchor" href="#七、三张表的关系" aria-label="Permalink to “七、三张表的关系”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>资产负债表（某一时点的照片）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>利润表（一段时间的录像）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>现金流量表（录像里真金白银的部分）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>三者要<strong>结合看</strong>，缺一不可。</p><h2 id="思考题" tabindex="-1">思考题 <a class="header-anchor" href="#思考题" aria-label="Permalink to “思考题”">​</a></h2><blockquote><p>某公司净利润很高，但经营现金流连续2年为负。可能是什么原因？这种公司能买吗？</p></blockquote><hr><p><strong>下一课预告</strong>：财报会看了，下一课学习<strong>常用估值指标</strong>——如何判断一只股票是贵还是便宜。</p>`,49)])])}const m=t(n,[["render",l]]);export{p as __pageData,m as default};
